const sd = $getWorkflowStaticData('global');
if (!sd.postedIds) sd.postedIds = [];
const eventId = String($('Execute Workflow Trigger').item.json.eventId);
if (!sd.postedIds.includes(eventId)) sd.postedIds.push(eventId);
return [{ json: { success: true, postedEventId: eventId } }];

